// src/pages/UserLogin.jsx
import React, { useState } from "react";
import { useNavigate, Link } from "react-router-dom";
import { sendOtp, verifyOtp } from "../api";

export default function UserLogin() {
  const [mobile, setMobile] = useState("");
  const [otp, setOtp] = useState("");
  const [step, setStep] = useState(1); // 1 = enter mobile, 2 = enter OTP
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const navigate = useNavigate();

  // Step 1 → Request OTP
  const handleSendOtp = async () => {
    try {
      setLoading(true);
      setError("");
      await sendOtp(mobile, "user");
      setStep(2);
    } catch (err) {
      setError(err.response?.data?.message || "Failed to send OTP");
    } finally {
      setLoading(false);
    }
  };

  // Step 2 → Verify OTP
  const handleVerifyOtp = async () => {
    try {
      setLoading(true);
      setError("");
      const res = await verifyOtp(mobile, otp, "user");

      // Save auth in localStorage
      localStorage.setItem("token", res.data.token || "dummy-token"); // ✅ replace with real token from backend
      localStorage.setItem("role", "user");

      // Navigate to user dashboard
      navigate("/user-dashboard");
    } catch (err) {
      setError(err.response?.data?.message || "Invalid OTP");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div style={{ maxWidth: 400, margin: "auto" }}>
      <h2>User Login</h2>

      {error && <p style={{ color: "red" }}>{error}</p>}

      {step === 1 && (
        <>
          <label>Mobile Number</label>
          <input
            type="text"
            value={mobile}
            onChange={(e) => setMobile(e.target.value)}
            placeholder="Enter mobile number"
          />
          <button onClick={handleSendOtp} disabled={loading || !mobile}>
            {loading ? "Sending..." : "Send OTP"}
          </button>
        </>
      )}

      {step === 2 && (
        <>
          <label>OTP</label>
          <input
            type="text"
            value={otp}
            onChange={(e) => setOtp(e.target.value)}
            placeholder="Enter OTP"
          />
          <button onClick={handleVerifyOtp} disabled={loading || !otp}>
            {loading ? "Verifying..." : "Verify OTP"}
          </button>
        </>
      )}

      <p>
        Don’t have an account? <Link to="/register">Sign up</Link>
      </p>
      <p>
        Are you a Rider? <Link to="/rider-login">Login as Rider</Link>
      </p>
    </div>
  );
}
